INSERT INTO public.questions (id, exam_id, paper_id, subject_id, chapter_id, question_type, question_text, options, correct_answer, correct_answer_json, auto_gradable, source, is_active, version, source_meta, explanation)
VALUES
  ('social-worker-moex-06550', 'social-worker', 'social-worker-moex-103-a62ebd66', 'sub-social-worker-04', NULL, 'single_choice', '研究者在建構研究工具時，需要良好的信度與效度，下列有關對研究工具信度的敘述，何者錯誤？ 我們可以在不同的時間用同一份測量工具對相同的一群人進行測量，如果前後兩次測量的結果都 相同，這就是一份有信度的測量工具 如果兩次測量間，發生前後不一致的現象，我們馬上就可以判斷這份研究工具是一份不具信度的 測量工具 有一份測量婚姻滿意度的問卷共有24個指標，如果我們要測量這份量表的信度，可將這份量表的 指標隨機拆成相同題數的兩半，即每一半各12個指標，如果這兩個部分施測後結果有很高的一致 性，便可說明這是一份具有信度的測量工具 一研究工具測量隨機誤差的多寡，會影響此研究工具的信度，愈可靠的研究工具其隨機誤差愈小', '["", "", "", ""]'::jsonb, 1, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:34+00:00", "source_pdf_sha1": "ae82baefbfac", "answer_pdf_sha1": "e85c59b48db8", "source_family": "moex-gov-tw", "moex": {"exam_code": "103100", "c": "110", "s": "0606", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作研究方法", "year": "103", "exam_name": "103年第二次專技醫師中醫師分階段、中醫師營養師心理師護理師社會工作師、法醫師語言聽力牙體技術師考試", "original_question_number": 13, "answer_corrected": false, "flags": ["incomplete_options"], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-06551', 'social-worker', 'social-worker-moex-103-a62ebd66', 'sub-social-worker-04', NULL, 'single_choice', '下列有關研究工具效度的敘述，何者錯誤？ 一份研究工具的「建構效度」是指測量工具符合某種理論與見解，建構效度可透過「趨同效度」 （convergent validity）與「區別效度」（discriminant validity）加以測量 一個研究測量工具的「表面效度」要比「內容效度」來得重要 以同學們在「高中學科成績」作為申請進入大學的依據，如果這些學生在大學的表現與高中成績 呈現高度的相關，可說高中學科成績具備「預測效度」 信度與效度之間存在一種緊張的關係，當測量某一概念或變項時，某一種測量工具可能信度很 好，但其效度不佳；也可能某一種測量工具效度很好，但其信度可能不佳', '["", "", "", ""]'::jsonb, 1, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:34+00:00", "source_pdf_sha1": "ae82baefbfac", "answer_pdf_sha1": "e85c59b48db8", "source_family": "moex-gov-tw", "moex": {"exam_code": "103100", "c": "110", "s": "0606", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作研究方法", "year": "103", "exam_name": "103年第二次專技醫師中醫師分階段、中醫師營養師心理師護理師社會工作師、法醫師語言聽力牙體技術師考試", "original_question_number": 14, "answer_corrected": false, "flags": ["incomplete_options"], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-06552', 'social-worker', 'social-worker-moex-103-a62ebd66', 'sub-social-worker-04', NULL, 'single_choice', '所有的社會工作研究者都希望研究的測量具有信度和效度，但很少有完美的信度。因此，在量化研', '["清楚界定所有概念", "提升測量等級", "使用多重的變項指 標", "使用前後測的比較"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:34+00:00", "source_pdf_sha1": "ae82baefbfac", "answer_pdf_sha1": "e85c59b48db8", "source_family": "moex-gov-tw", "moex": {"exam_code": "103100", "c": "110", "s": "0606", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作研究方法", "year": "103", "exam_name": "103年第二次專技醫師中醫師分階段、中醫師營養師心理師護理師社會工作師、法醫師語言聽力牙體技術師考試", "original_question_number": 15, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-06553', 'social-worker', 'social-worker-moex-103-a62ebd66', 'sub-social-worker-04', NULL, 'single_choice', '下列有關測量等級的敘述，何者正確？ 測量的等級由最精確到較不精確的等級依次為等距、比率、順序、名目四個等級 連續變項可以由等距或比率等級的變項加以測量；間斷變項可由名目或順序等級的變項加以測量 等距變項有真正的零點，比率變項則只有相對的零點 較高層次的等級，可轉化為較低層次等級，反之亦然', '["", "", "", ""]'::jsonb, 1, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:34+00:00", "source_pdf_sha1": "ae82baefbfac", "answer_pdf_sha1": "e85c59b48db8", "source_family": "moex-gov-tw", "moex": {"exam_code": "103100", "c": "110", "s": "0606", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作研究方法", "year": "103", "exam_name": "103年第二次專技醫師中醫師分階段、中醫師營養師心理師護理師社會工作師、法醫師語言聽力牙體技術師考試", "original_question_number": 16, "answer_corrected": false, "flags": ["incomplete_options"], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-06554', 'social-worker', 'social-worker-moex-103-a62ebd66', 'sub-social-worker-04', NULL, 'single_choice', '從下列問卷中的題項與選項中，那一問項同時符合「周延」與「互斥」的選項分類原則？', '["2萬~3萬以下", "3萬~5萬以下", "5萬~8萬以下", "8萬（含）以上 您的年齡："]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:34+00:00", "source_pdf_sha1": "ae82baefbfac", "answer_pdf_sha1": "e85c59b48db8", "source_family": "moex-gov-tw", "moex": {"exam_code": "103100", "c": "110", "s": "0606", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作研究方法", "year": "103", "exam_name": "103年第二次專技醫師中醫師分階段、中醫師營養師心理師護理師社會工作師、法醫師語言聽力牙體技術師考試", "original_question_number": 17, "answer_corrected": true, "flags": ["answer_corrected_skip_v1"], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-06555', 'social-worker', 'social-worker-moex-103-a62ebd66', 'sub-social-worker-04', NULL, 'single_choice', '下列問卷調查中的問項（item），那一個問項是沒有偏差（bias）的？ 您是否同意政府應提高房屋稅、地價稅，降低汽車燃料稅、牌照稅以縮小貧富差距 您是否欺騙過自己的配偶 您的性別 您第一次頂撞父母是什麼時候', '["", "", "", ""]'::jsonb, 2, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:34+00:00", "source_pdf_sha1": "ae82baefbfac", "answer_pdf_sha1": "e85c59b48db8", "source_family": "moex-gov-tw", "moex": {"exam_code": "103100", "c": "110", "s": "0606", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作研究方法", "year": "103", "exam_name": "103年第二次專技醫師中醫師分階段、中醫師營養師心理師護理師社會工作師、法醫師語言聽力牙體技術師考試", "original_question_number": 18, "answer_corrected": false, "flags": ["incomplete_options"], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-06556', 'social-worker', 'social-worker-moex-103-a62ebd66', 'sub-social-worker-04', NULL, 'single_choice', '當社會工作研究者進行測量時，會將概念、想法或觀念聯繫到測量上，藉此可以具體觀察這些概 念。下列敘述何者錯誤？ 量化研究是抽象概念→利用一套測量過程→把概念展現為具體的資料 質化研究是經驗資料→抽象的觀念、相關的概念和資料→呈現出概念與資料的混合 量化研究的測量過程，呈現出先概念化，後操作化，再運用操作化定義或測量蒐集資料 質化研究中，概念化主要是由資料來決定，而操作化是一種事前的描述，也是事前設想的技術', '["", "", "", ""]'::jsonb, 3, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:34+00:00", "source_pdf_sha1": "ae82baefbfac", "answer_pdf_sha1": "e85c59b48db8", "source_family": "moex-gov-tw", "moex": {"exam_code": "103100", "c": "110", "s": "0606", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作研究方法", "year": "103", "exam_name": "103年第二次專技醫師中醫師分階段、中醫師營養師心理師護理師社會工作師、法醫師語言聽力牙體技術師考試", "original_question_number": 19, "answer_corrected": false, "flags": ["incomplete_options"], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-06557', 'social-worker', 'social-worker-moex-103-a62ebd66', 'sub-social-worker-04', NULL, 'single_choice', '變項是量化研究中的核心之一，所以下列何者正確？①變項係一個不變的概念  ②量化研究會使用', '["依變項是獨立於先前產生作用的其他自變項", "中介變項作用的方 式係對自變項而言，其角色為依變項；對依變項而言，卻是自變項的角色", "", ""]'::jsonb, 2, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:34+00:00", "source_pdf_sha1": "ae82baefbfac", "answer_pdf_sha1": "e85c59b48db8", "source_family": "moex-gov-tw", "moex": {"exam_code": "103100", "c": "110", "s": "0606", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作研究方法", "year": "103", "exam_name": "103年第二次專技醫師中醫師分階段、中醫師營養師心理師護理師社會工作師、法醫師語言聽力牙體技術師考試", "original_question_number": 20, "answer_corrected": false, "flags": ["incomplete_options"], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-06558', 'social-worker', 'social-worker-moex-103-a62ebd66', 'sub-social-worker-04', NULL, 'single_choice', '下列實驗設計針對的對象，何者敘述錯誤？ 寬心劑（或安慰劑，placebo）針對的對象是接受實驗者 雙盲設計（double blind）針對的對象是實驗者 隨機分派（randomization）的對象是接受實驗者 單案設計（single case design）針對的是單一個案實驗的實驗對象', '["", "", "", ""]'::jsonb, 1, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:34+00:00", "source_pdf_sha1": "ae82baefbfac", "answer_pdf_sha1": "e85c59b48db8", "source_family": "moex-gov-tw", "moex": {"exam_code": "103100", "c": "110", "s": "0606", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作研究方法", "year": "103", "exam_name": "103年第二次專技醫師中醫師分階段、中醫師營養師心理師護理師社會工作師、法醫師語言聽力牙體技術師考試", "original_question_number": 21, "answer_corrected": false, "flags": ["incomplete_options"], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-06559', 'social-worker', 'social-worker-moex-103-a62ebd66', 'sub-social-worker-04', NULL, 'single_choice', '下列有關傳統的實驗法的敘述，何者錯誤？ 通常實驗的對象是透過隨機抽樣（random sampling），將實驗對象分成實驗組與控制組 通常實驗的刺激（或介入、處遇）只給實驗組，控制組則無刺激，這個刺激是實驗者可以操弄的 自變項 實驗過程通常有前測與後測，前測的目的是確保起始點兩組實驗對象在實驗觀察的依變項是相同 或接近的；後測是比較在有、無刺激的情況下兩組是否在依變項上產生差異 如果兩組在後測上的表現出現顯著的差異，研究者在確定排除其他可能的干擾後可以把差異歸因 於自變項', '["", "", "", ""]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:34+00:00", "source_pdf_sha1": "ae82baefbfac", "answer_pdf_sha1": "e85c59b48db8", "source_family": "moex-gov-tw", "moex": {"exam_code": "103100", "c": "110", "s": "0606", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作研究方法", "year": "103", "exam_name": "103年第二次專技醫師中醫師分階段、中醫師營養師心理師護理師社會工作師、法醫師語言聽力牙體技術師考試", "original_question_number": 22, "answer_corrected": false, "flags": ["incomplete_options"], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL)
